  },
  deniz: {
    name: 'Deniz Traumfänger', typ: 'bonus', woerter: '150–300',
    bonus: true,
    imgUrl: 'https://rala84.github.io/lesekumpel/avatars/deniz-traumfaenger.webp',
    bio: 'Deniz nimmt dich mit in magische Welten voller Atmosphäre und Gefühle.'
  },
  jonas: {
