parameters.jsCode:
const prev = $('Geschichte parsen').first().json;
const rawText = $input.item.json.text || '';

let wortschatz = [], tags = [];
try {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) { const p = JSON.parse(m[0]); wortschatz = p.wortschatz || []; tags = p.tags || []; }
} catch(e) { tags = [prev.genre]; }

return { json: { ...prev, wortschatz, tags } };

const prev = $('Linguistik parsen').first().json;
const rawText = $input.item.json.text || '';

let quizData = [];
try { const m = rawText.match(/\[[\s\S]*\]/); if (m) quizData = JSON.parse(m[0]); } catch(e) {}

return { json: { ...prev, quizData } };

const prevData = $('Bildszenen vorbereiten').first().json;
if (prevData.skipImages || prevData.imageCount === 0) {
  return [{ json: { ...prevData, _skipLoop: true } }];
}

const prev = $('Bildszenen vorbereiten').first().json;
const rawText = $input.first().json.text || '';
const charRef = prev.characterReference || '';

// Central youth-protection framing — applied to every prompt regardless of story or style
// Clothing wording is type-aware: only enforced when human characters are present.
const _hasNonHuman = !!prev.hasNonHumanCharacter;
const _clothingClause = _hasNonHuman
  ? 'human characters are fully clothed in everyday outfits, animal characters are real animals with no clothing and no costume'
  : 'fully clothed characters in everyday outfits';
const safetyContext = "Wholesome G-rated illustration for a published German children's picture book, age-appropriate storybook art, " + _clothingClause;
const safetyNegative = 'no swimwear, no swimsuit, no bikini, no underwear, no nudity, no bare torso, no exposed skin beyond face and hands, no animals depicted as humans, no children wearing animal costumes';

let scenes = [];
try { const m = rawText.match(/\[[\s\S]*\]/); if (m) scenes = JSON.parse(m[0]); } catch(e) {}

if (!Array.isArray(scenes) || scenes.length === 0) {
  scenes = [{
    scene: 1,
    positive: (prev.imageStylePositive || "children's book illustration") + ". Character: " + charRef + ". A friendly scene from the story '" + (prev.title || '') + "', child-safe.",
    negative: prev.imageStyleNegative || "no text, no watermarks, no extra limbs"
  }];
}

return scenes.map(s => {
  let positive = s.positive || s.prompt || '';
  const negative = s.negative || prev.imageStyleNegative || '';

  if (charRef && !positive.includes(charRef.substring(0, 30))) {
    positive = charRef + '. Scene: ' + positive;
  }
  positive = safetyContext + '. ' + positive;

  const fullNegative = negative ? (negative + ', ' + safetyNegative) : safetyNegative;
  const finalPrompt = positive + ' | NEGATIVE: ' + fullNegative;

  return {
    json: {
      ...prev,
      sceneIndex: s.scene,
      imagePrompt: finalPrompt,
      imageFilename: prev.slug + '-' + s.scene + '.png',
      imageGithubPath: 'bilder/' + prev.slug + '-' + s.scene + '.png',
      geminiRequestBody: {
        contents: [{ role: 'user', parts: [{ text: finalPrompt }] }],
        generationConfig: { responseModalities: ['image', 'text'] }
      }
    }
  };
});

// Daten aus Quiz parsen + emojiStoryText aus Emoji parsen
const quizData = $('Schatz parsen').first().json;
const emojiData = $('Emoji parsen').first().json;
const data = { ...quizData, emojiStoryText: emojiData.emojiStoryText || quizData.storyText || '' };
// Image-Modell aus Probe-Auswertung (Scout-Pattern): gpt-image-2 oder gemini-2.5-flash-image
data.imageModel = ($('Probe auswerten').first()?.json?.imageModel) || 'unknown';

let template = $input.item.json.data;

// Generate image tags
const imageCount = data.imageCount || 0;
let imagesHtml = '';
for (let i = 1; i <= imageCount; i++) {
  const imgUrl = `https://rala84.github.io/lesekumpel/bilder/${data.slug}-${i}.png`;
  imagesHtml += `<img src="${imgUrl}" alt="${data.title}" class="hero-image" onerror="this.style.display='none'">\n        `;
}

template = template
  .replace(/\{\{STORY_TITLE\}\}/g, data.title || '')
  .replace(/\{\{STORY_DATE\}\}/g, data.date || '')
  .replace(/\{\{PERSONA_NAME\}\}/g, data.personaName || '')
  .replace(/\{\{PERSONA_IMG_URL\}\}/g, data.personaImg || '')
  .replace(/\{\{PERSONA_BIO\}\}/g, data.personaBio || '')
  .replace(/\{\{NEUROTYP\}\}/g, data.neurotyp || '')
  .replace(/\{\{GENRE\}\}/g, data.genre || '')
  .replace(/\{\{STORY_IMAGES_HTML\}\}/g, imagesHtml.trim())
  .replace(/\{\{HERO_IMAGE_URL\}\}/g, `https://rala84.github.io/lesekumpel/bilder/${data.slug}-1.png`)
  .replace(/\{\{RAW_STORY_TEXT\}\}/g, JSON.stringify(data.storyText || ''))
  .replace(/\{\{EMOJI_STORY_TEXT\}\}/g, JSON.stringify(data.emojiStoryText || ''))
  .replace(/\{\{RAW_SUMMARY_TEXT\}\}/g, JSON.stringify(data.summaryText || ''))
  .replace(/\{\{QUIZ_DATA_JSON\}\}/g, JSON.stringify(data.quizData || []))
  .replace(/\{\{WEITERERZAEHLEN_JSON\}\}/g, JSON.stringify(data.weitererzaehlenData || null))
  .replace(/\{\{SCHATZSUCHE_JSON\}\}/g, JSON.stringify(data.schatzsucheData || null))
  .replace(/\{\{DICTIONARY_JSON\}\}/g, JSON.stringify(data.wortschatz || []))
  .replace(/\{\{WORD_COUNT\}\}/g, String(data.wordCount || 0))
  .replace(/\{\{IMAGE_MODEL\}\}/g, data.imageModel || '')
  .replace(/\{\{SLUG\}\}/g, data.slug || '')
  .replace(/\{\{RELATED_STORIES_HTML\}\}/g, '');

const htmlBase64 = Buffer.from(template, 'utf8').toString('base64');
const storyUrl = `https://rala84.github.io/lesekumpel/demo-texte/${data.slug}.html`;

return { json: { ...data, htmlBase64, filePath: `demo-texte/${data.slug}.html`, commitMessage: `Demo-Text: ${data.title} — ${data.personaName} ${data.neurotyp || ''}`.trim(), storyUrl } };

const prev = $('Story-Elemente vorbereiten').first().json;
const rawText = $input.first().json.text || '';

let storyElements = { characters: [], props: [], setting: '', sceneRules: [] };
try {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) storyElements = JSON.parse(m[0]);
} catch(e) {}

if (!Array.isArray(storyElements.sceneRules)) storyElements.sceneRules = [];

function countWord(n) {
  if (typeof n !== "number") return "";
  const map = {1:"one",2:"two",3:"three",4:"four",5:"five",6:"six",7:"seven",8:"eight",9:"nine"};
  return map[n] || String(n);
}
function handPhrase(heldIn) {
  if (!heldIn || heldIn === "none") return "";
  if (heldIn === "both hands") return " held in both hands";
  if (heldIn === "left hand" || heldIn === "right hand") return " held in the " + heldIn;
  return " " + heldIn;
}

const clothingRegex = new RegExp("\\b(wearing|shirt|dress|trousers|pants|shorts|jacket|hoodie|coat|sweater|skirt|outfit|clothes|kleidung)\\b", "i");

function describeCharacter(c) {
  const type = (c.type || 'human').toLowerCase();
  const appearance = (c.appearance || "").trim();

  if (type === 'animal') {
    const species = c.species || 'animal';
    // Real animal — explicit anti-anthropomorphism. Do NOT add clothing.
    return c.name + " (real " + species + ", anatomically accurate animal — NOT a person, NOT a child, NOT in costume, no clothing): " + appearance;
  }

  if (type === 'creature') {
    const species = c.species || 'fantasy creature';
    return c.name + " (fantasy " + species + ", picture-book creature): " + appearance;
  }

  if (type === 'object') {
    return c.name + " (inanimate object): " + appearance;
  }

  // Default: human
  const sizeHint = c.heightCategory
    ? " (" + c.heightCategory + " character in a children picture book)"
    : " (childrens picture book character)";
  let humanAppearance = appearance;
  // Force clothing if LLM omitted it — applies to HUMANS ONLY (animals/creatures handled above).
  if (!clothingRegex.test(humanAppearance)) {
    humanAppearance = (humanAppearance ? humanAppearance + "; " : "") + "wearing a casual t-shirt and shorts/trousers, fully clothed";
  }
  return c.name + sizeHint + ": " + humanAppearance;
}

let charRef = "";
if (storyElements.characters && storyElements.characters.length > 0) {
  charRef = storyElements.characters.map(describeCharacter).join(". ");
}
if (storyElements.props && storyElements.props.length > 0) {
  charRef += ". Props: " + storyElements.props
    .map(p => {
      const word = countWord(p.count);
      const qty = word ? word + " " : "";
      const nameLower = (p.name || "").toString().toLowerCase();
      const hand = handPhrase(p.heldIn);
      const prefix = (qty + nameLower).trim();
      return prefix + hand + ": " + (p.description || "");
    })
    .join(". ");
}
if (storyElements.setting) {
  charRef += ". Setting: " + storyElements.setting;
}

const sceneRules = storyElements.sceneRules.filter(r => typeof r === "string" && r.length > 0);

// Forward a flag downstream so safety context can be type-aware
const hasNonHumanCharacter = (storyElements.characters || []).some(c => {
  const t = (c.type || 'human').toLowerCase();
  return t === 'animal' || t === 'creature';
});

return { json: { ...prev, storyElements, characterReference: charRef, sceneRules, hasNonHumanCharacter } };

const origData = $('Geschichte parsen').first().json;
const taggerOutput = $input.item.json.text || '[]';
const rawText = origData.rawStoryText || '';

// Parse Emoji-Annotations
let annotations = [];
try {
  const m = taggerOutput.match(/\[[\s\S]*\]/);
  if (m) annotations = JSON.parse(m[0]);
} catch(e) {
  console.warn('EMOJI-PARSE: JSON parse error:', e.message);
  console.warn('EMOJI-PARSE: Tagger output was:', taggerOutput.substring(0, 500));
}

// Fallback: rule-based emoji insertion if LLM returned nothing
if (!Array.isArray(annotations) || annotations.length === 0) {
  const fallbackMap = [
    { wort: 'froh', emoji: '😊' }, { wort: 'fröhlich', emoji: '😊' },
    { wort: 'glücklich', emoji: '😊' }, { wort: 'freut', emoji: '😊' },
    { wort: 'lacht', emoji: '😊' }, { wort: 'lachte', emoji: '😊' },
    { wort: 'traurig', emoji: '😢' }, { wort: 'weint', emoji: '😢' },
    { wort: 'weinte', emoji: '😢' }, { wort: 'vermisst', emoji: '😢' },
    { wort: 'enttäuscht', emoji: '😢' },
    { wort: 'wütend', emoji: '😠' }, { wort: 'sauer', emoji: '😠' },
    { wort: 'ärgert', emoji: '😠' },
    { wort: 'Angst', emoji: '😨' }, { wort: 'erschrocken', emoji: '😨' },
    { wort: 'ängstlich', emoji: '😨' }, { wort: 'fürchtet', emoji: '😨' },
    { wort: 'überrascht', emoji: '😮' }, { wort: 'erstaunt', emoji: '😮' },
    { wort: 'nervös', emoji: '😰' }, { wort: 'unsicher', emoji: '😰' },
    { wort: 'aufgeregt', emoji: '😰' },
    { wort: 'mutig', emoji: '💪' }, { wort: 'traut', emoji: '💪' },
    { wort: 'frustriert', emoji: '😤' }, { wort: 'genervt', emoji: '😤' },
    { wort: 'erleichtert', emoji: '😌' }, { wort: 'beruhigt', emoji: '😌' },
    { wort: 'stolz', emoji: '😏' }, { wort: 'zufrieden', emoji: '😏' },
    { wort: 'liebt', emoji: '🥰' }, { wort: 'mag', emoji: '🥰' },
  ];
  const lowerText = rawText.toLowerCase();
  for (const entry of fallbackMap) {
    if (lowerText.includes(entry.wort.toLowerCase())) {
      annotations.push(entry);
    }
  }
  if (annotations.length > 0) {
    console.log('EMOJI-PARSE: Used rule-based fallback, found ' + annotations.length + ' emotion words');
  }
}

// Insert emojis into original text (deterministic, no LLM rewriting)
let emojiText = rawText;
if (Array.isArray(annotations) && annotations.length > 0) {
  // Sort by position in text (last first to preserve indices)
  const positions = [];
  for (const a of annotations) {
    if (!a.wort || !a.emoji) continue;
    // Find all occurrences of this word in the text
    let searchFrom = 0;
    while (true) {
      const idx = emojiText.indexOf(a.wort, searchFrom);
      if (idx === -1) break;
      // Check if emoji already inserted after this word
      const afterWord = idx + a.wort.length;
      if (emojiText[afterWord] !== ' ' || !isEmoji(emojiText[afterWord + 1])) {
        positions.push({ idx: afterWord, emoji: a.emoji, wort: a.wort });
      }
      searchFrom = idx + a.wort.length + 1;
      break; // Only first occurrence per annotation
    }
  }

  // Sort descending so we insert from end to start (preserves indices)
  positions.sort((a, b) => b.idx - a.idx);

  for (const p of positions) {
    emojiText = emojiText.substring(0, p.idx) + ' ' + p.emoji + emojiText.substring(p.idx);
  }
}

function isEmoji(char) {
  if (!char) return false;
  const cp = char.codePointAt(0);
  return cp > 0x1F000;
}

// Apply Silbentrennung to emoji text
function silbentrennung(wort) {
  if (wort.length <= 3) return wort;
  if (!/^[a-zäöüß]+$/i.test(wort)) return wort;
  const w = wort.toLowerCase();
  const einheiten = [];
  let i = 0;
  while (i < w.length) {
    if (i+2 < w.length && w.substring(i, i+3) === 'sch') { einheiten.push({text:w.substring(i,i+3),typ:'K',pos:i,len:3}); i+=3; continue; }
    const zwei = i+1<w.length ? w.substring(i,i+2) : '';
    if (['ch','ck','ph','th','qu','pf'].includes(zwei)) { einheiten.push({text:zwei,typ:'K',pos:i,len:2}); i+=2; continue; }
    if (['ei','au','eu','äu','ie','ai'].includes(zwei)) { einheiten.push({text:zwei,typ:'V',pos:i,len:2}); i+=2; continue; }
    const vokal = 'aeiouyäöü'.includes(w[i]);
    einheiten.push({text:w[i],typ:vokal?'V':'K',pos:i,len:1}); i++;
  }
  const vokalIndices = [];
  for (let e=0; e<einheiten.length; e++) {
    if (einheiten[e].typ==='V') {
      if (vokalIndices.length>0 && vokalIndices[vokalIndices.length-1].end===e) vokalIndices[vokalIndices.length-1].end=e+1;
      else vokalIndices.push({start:e,end:e+1});
    }
  }
  if (vokalIndices.length<2) return wort;
  const trennstellen = [];
  for (let v=0; v<vokalIndices.length-1; v++) {
    const nachVokal = vokalIndices[v].end;
    const vorVokal = vokalIndices[v+1].start;
    const anzahlKons = vorVokal - nachVokal;
    let trennEinheit;
    if (anzahlKons===0) trennEinheit=nachVokal;
    else if (anzahlKons===1) trennEinheit=nachVokal;
    else { trennEinheit=vorVokal-1;
      if (anzahlKons>=2) { const vl=einheiten[vorVokal-2]; const lt=einheiten[vorVokal-1];
        if (vl.text==='s'&&lt.text==='t') trennEinheit=vorVokal-2;
      }
    }
    const charPos = einheiten[trennEinheit].pos;
    if (charPos>0 && charPos<wort.length) trennstellen.push(charPos);
  }
  if (!trennstellen.length) return wort;
  let erg='', letzte=0;
  for (const pos of trennstellen) { erg+=wort.substring(letzte,pos)+'-'; letzte=pos; }
  return erg+wort.substring(letzte);
}

const emojiStoryText = emojiText.replace(/[a-zäöüßA-ZÄÖÜ]{4,}/g, (w) => silbentrennung(w));

return { json: { ...origData, emojiStoryText } };

const prev = $input.first().json;

if (!prev.imageCount || prev.imageCount === 0) {
  return [{ json: { ...prev, skipImages: true } }];
}

const charRef = prev.characterReference || '';
const imageStylePositive = prev.imageStylePositive || "children's book watercolor illustration, soft pastel colors, consistent rendering across all panels of this story: same line weight, same color palette, same character proportions and facial features";
const imageStyleNegative = prev.imageStyleNegative || "no text, no watermarks, no extra limbs, no duplicate props, no floating objects, no mixed art styles, no style drift";
const imageCount = prev.imageCount || 1;
const sceneRules = Array.isArray(prev.sceneRules) ? prev.sceneRules : [];

const rulesBlock = sceneRules.length > 0
  ? sceneRules.map((r, i) => `${i+1}. ${r}`).join('\n')
  : '(no explicit invariants — infer plausibility from story)';

const sceneUserPrompt = `You are a prompt compiler for a children's book illustrator. Fill the slot template below. Do NOT write free prose.

ART STYLE (positive):
${imageStylePositive}

ART STYLE (negative):
${imageStyleNegative}

CHARACTER REFERENCE (repeat exactly in EVERY scene):
${charRef}

SCENE INVARIANTS (global rules that apply to EVERY scene as constraints, NOT as actions to depict):
${rulesBlock}

STORY TEXT:
${prev.storyText || ''}

TASK: Output a JSON array with exactly ${imageCount} objects. Pick ${imageCount} distinct moment(s) from the story that together cover the story arc. Each scene shows exactly ONE moment — never combine two moments into one image, never show the same character twice.

Each object has this shape:
{
  "scene": <1-based number>,
  "momentSummary": "<one English sentence naming the single story moment this scene depicts>",
  "positive": "<ART_STYLE_POSITIVE>. Characters present (repeat description verbatim from CHARACTER REFERENCE for each — humans keep clothing, animals keep real animal anatomy with NO clothing and NO costume): <CHAR_REF_SUBSET>. Ages: <explicit age for every HUMAN character; for animals write \"real animal — no age\">. Composition: <camera angle>, <action verb>. Spatial: <ON|NEXT-TO|BEHIND|IN-FRONT-OF> <object>. Props in hands: left=<X or none>, right=<Y or none>. Setting: <location>. Mood: <adjective>.",
  "negative": "<ART_STYLE_NEGATIVE>, wrong ages, duplicate props, floating objects, extra characters not in the story, same character shown more than once, animals depicted as humans in costume, anthropomorphic animals unless explicitly stated in the story",
  "invariantCheck": "<one English sentence asserting this scene respects every SCENE INVARIANT above>",
  "compositionCheck": "<one English sentence asserting this scene is a full-bleed square 1:1 image with artwork reaching all four corners, no white margin, no inner matte>"
}

CHECKS for every scene:
1. Spatial relation is explicit (ON / NEXT-TO / BEHIND / IN-FRONT-OF).
2. Every named prop shown has a hand slot (left / right / both / none).
3. Every HUMAN character has an explicit age that matches the story; animals are rendered as actual animals with real anatomy, not as humans in costume.
4. Only include characters named in the story; do not invent extras.
5. Each named character appears AT MOST ONCE in the scene — never duplicate a character.
6. Scene depicts exactly ONE moment from the story; do not combine moments.
7. Camera angle and setting vary between scenes; character appearance stays identical.

Output ONLY the JSON array, no markdown, no explanation.`;

return [{ json: { ...prev, sceneUserPrompt } }];

const prev = $('Quiz parsen').first().json;
const rawText = $input.item.json.text || '';

let weitererzaehlenData = null;
try { const m = rawText.match(/\{[\s\S]*\}/); if (m) weitererzaehlenData = JSON.parse(m[0]); } catch(e) {}

return { json: { ...prev, weitererzaehlenData } };

const prev = $('Weiterdenken parsen').first().json;
const rawText = $input.item.json.text || '';

let schatzsucheData = null;
try { const m = rawText.match(/\{[\s\S]*\}/); if (m) schatzsucheData = JSON.parse(m[0]); } catch(e) {}

// Normalize: schatzwoerter lowercase, strip hyphens/punct
if (schatzsucheData && Array.isArray(schatzsucheData.schatzwoerter)) {
  schatzsucheData.schatzwoerter = schatzsucheData.schatzwoerter
    .map(w => (w || '').toString().toLowerCase().replace(/[-.,!?:;„"()]/g, '').trim())
    .filter(w => w.length > 0);
}

return { json: { ...prev, schatzsucheData } };

// Auswertung der Probe-Generierung mit gpt-image-2.
// Bei Erfolg: erste Szene erhält den Probe-b64 (wird wiederverwendet),
// Bei Misserfolg: alle Szenen werden mit Gemini-Fallback markiert.
const probeResp = $input.first()?.json || {};
const probeSuccess = !!(probeResp && probeResp.data && probeResp.data[0] && probeResp.data[0].b64_json);
const probeB64 = probeSuccess ? probeResp.data[0].b64_json : null;

const allItems = $('Szenen parsen').all().map(it => it.json);
if (allItems.length === 0) {
  return [];
}

if (probeSuccess) {
  return allItems.map((item, idx) => ({
    json: {
      ...item,
      useFallback: false,
      prefilledB64: idx === 0 ? probeB64 : null,
      probeOutcome: 'openai-success',
      imageModel: 'gpt-image-2'
    }
  }));
} else {
  return allItems.map(item => ({
    json: {
      ...item,
      useFallback: true,
      prefilledB64: null,
      probeOutcome: 'openai-blocked',
      imageModel: 'gemini-2.5-flash-image'
    }
  }));
}
